  "dg.title1": "Các ứng dụng khác hỏi bạn đã mơ gì.",
  "dg.title2": "DreamGuard đã biết rồi.",
  "dg.subtitle": "Trong khi bạn ngủ, DreamGuard hoạt động. Micro thu nhận các rung động và âm thanh — yên tĩnh, an toàn, cục bộ.",
  "dg.feat1.title": "Nhận diện ngôn ngữ giấc ngủ",
  "dg.feat1.desc": "Bạn nói chuyện trong khi ngủ? DreamGuard tự động phiên âm. Buổi sáng bạn sẽ thấy những gì bạn đã nói — liên kết với giấc mơ của bạn.",
  "dg.feat2.title": "Phát hiện cảm xúc",
  "dg.feat2.desc": "KI/AI phân tích âm điệu: sợ hãi, vui vẻ, buồn bã, căng thẳng. Điểm cảm xúc ban đêm của bạn: \"73% bình tĩnh · 27% tín hiệu căng thẳng\"",
  "dg.feat3.title": "Thời điểm đánh thức tối ưu",
  "dg.feat3.desc": "Phân tích nhịp thở nhận diện các giai đoạn giấc ngủ. Báo thức nhẹ nhàng trong giai đoạn ngủ nông — không đánh thức thô bạo giữa giấc ngủ sâu.",
  "dg.feat4.title": "Dream Trigger",
  "dg.feat4.desc": "Nhịp điệu hai tai và tần số nhẹ nhàng trong giấc ngủ REM — được khoa học chứng minh là phương pháp để ảnh hưởng đến nội dung giấc mơ.",
  "dg.privacy": "Mọi thứ 100% cục bộ trên thiết bị của bạn — không có dữ liệu âm thanh nào rời khỏi điện thoại của bạn. Tuân thủ DSGVO/GDPR.",
  "dg.apkExclusive": "APK ĐỘC QUYỀN",
  "dg.apkNote": "DreamGuard chỉ khả dụng cho tải xuống APK trực tiếp — không có trên cửa hàng.",
